<template>
  <div v-if="isOpen" class="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 shadow-2xl z-50 p-6 md:p-8">
    <div class="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
      <div class="flex-1">
        <h3 class="text-lg font-bold text-slate-900 mb-2">We value your privacy</h3>
        <p class="text-slate-600 text-sm leading-relaxed">
          We use cookies to enhance your browsing experience, serve personalized ads or content, and analyze our traffic. 
          By clicking "Accept All", you consent to our use of cookies. 
          <router-link to="/privacy" class="text-blue-600 hover:underline">Read our Privacy Policy</router-link>.
        </p>
      </div>
      <div class="flex gap-4">
        <button 
          @click="acceptCookies" 
          class="bg-blue-600 text-white px-6 py-2.5 rounded-lg font-bold text-sm hover:bg-blue-700 transition-colors shadow-sm"
        >
          Accept All
        </button>
        <button 
          @click="declineCookies" 
          class="bg-white text-slate-700 border border-slate-300 px-6 py-2.5 rounded-lg font-bold text-sm hover:bg-slate-50 transition-colors"
        >
          Decline
        </button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'

const isOpen = ref(false)

onMounted(() => {
  const consent = localStorage.getItem('tholution_cookie_consent')
  if (!consent) {
    isOpen.value = true
  }
})

const acceptCookies = () => {
  localStorage.setItem('tholution_cookie_consent', 'accepted')
  isOpen.value = false
}

const declineCookies = () => {
  localStorage.setItem('tholution_cookie_consent', 'declined')
  isOpen.value = false
}
</script>
